import {
  Controller,
  Get,
  Post,
  Body,
  Param,
  Query,
  Headers,
  Req,
  UseGuards,
  HttpCode,
  HttpStatus,
  UnauthorizedException,
  InternalServerErrorException,
  Logger,
} from '@nestjs/common';
import {
  ApiTags,
  ApiOperation,
  ApiResponse,
  ApiBearerAuth,
  ApiParam,
  ApiQuery,
} from '@nestjs/swagger';
import { ConfigService } from '@nestjs/config';
import { Throttle } from '@nestjs/throttler';
import { InjectQueue } from '@nestjs/bullmq';
import { Queue } from 'bullmq';
import { Request } from 'express';
import * as crypto from 'crypto';
import { JwtAuthGuard } from '../auth/guards/jwt-auth.guard';
import { RolesGuard, UserRole } from '../auth/guards/roles.guard';
import { Roles } from '../auth/decorators/roles.decorator';
import { CurrentTenant } from '../auth/decorators/current-user.decorator';
import { MetricsService } from '../common/metrics/metrics.service';
import { SmsThreadService } from './sms-thread.service';
import {
  SendSmsDto,
  InboundSmsDto,
  SmsThreadResponseDto,
  SmsMessageResponseDto,
} from './dto/sms.dto';

@ApiTags('SMS')
@ApiBearerAuth()
@UseGuards(JwtAuthGuard, RolesGuard)
@Roles(UserRole.ADMIN, UserRole.MECHANIC)
@Controller('sms')
export class SmsThreadController {
  constructor(private readonly smsThreadService: SmsThreadService) {}

  @Get('threads')
  @ApiOperation({ summary: 'List SMS threads' })
  @ApiQuery({ name: 'limit', required: false, type: Number })
  @ApiQuery({ name: 'offset', required: false, type: Number })
  @ApiResponse({ status: 200, description: 'Threads retrieved successfully' })
  async getThreads(
    @CurrentTenant() tenantId: string,
    @Query('limit') limit?: number,
    @Query('offset') offset?: number,
  ): Promise<{ success: boolean; data: SmsThreadResponseDto[]; meta: { total: number } }> {
    const result = await this.smsThreadService.getThreads(tenantId, limit, offset);
    return {
      success: true,
      data: result.threads,
      meta: { total: result.total },
    };
  }

  @Get('threads/:id/messages')
  @ApiOperation({ summary: 'Get messages for a thread' })
  @ApiParam({ name: 'id', description: 'Thread ID' })
  @ApiQuery({ name: 'limit', required: false, type: Number })
  @ApiQuery({ name: 'offset', required: false, type: Number })
  @ApiResponse({ status: 200, description: 'Messages retrieved successfully' })
  @ApiResponse({ status: 404, description: 'Thread not found' })
  async getMessages(
    @CurrentTenant() tenantId: string,
    @Param('id') threadId: string,
    @Query('limit') limit?: number,
    @Query('offset') offset?: number,
  ): Promise<{ success: boolean; data: SmsMessageResponseDto[]; meta: { total: number } }> {
    const result = await this.smsThreadService.getMessages(tenantId, threadId, limit, offset);
    return {
      success: true,
      data: result.messages,
      meta: { total: result.total },
    };
  }

  @Post('threads/:id/send')
  @HttpCode(HttpStatus.OK)
  @ApiOperation({ summary: 'Send SMS message in a thread' })
  @ApiParam({ name: 'id', description: 'Thread ID' })
  @ApiResponse({ status: 200, description: 'Message sent successfully' })
  @ApiResponse({ status: 404, description: 'Thread not found' })
  async sendMessage(
    @CurrentTenant() tenantId: string,
    @Param('id') threadId: string,
    @Body() dto: SendSmsDto,
  ): Promise<{ success: boolean; data: unknown }> {
    const message = await this.smsThreadService.sendMessage(tenantId, threadId, dto.body);
    return {
      success: true,
      data: message,
    };
  }
}

/**
 * Twilio inbound webhook controller — no auth guard.
 * Verifies Twilio request signature using HMAC-SHA1 (X-Twilio-Signature header).
 * Enqueues inbound SMS for async processing via BullMQ.
 */
@ApiTags('SMS Webhooks')
@Controller('sms/webhook')
export class SmsWebhookController {
  private readonly logger = new Logger(SmsWebhookController.name);

  constructor(
    private readonly configService: ConfigService,
    private readonly metricsService: MetricsService,
    @InjectQueue('sms-inbound') private readonly smsQueue: Queue,
  ) {}

  @Post('inbound/:tenantId')
  @HttpCode(HttpStatus.OK)
  @Throttle({ default: { ttl: 60000, limit: 30 } })
  @ApiOperation({ summary: 'Twilio inbound SMS webhook' })
  @ApiParam({ name: 'tenantId', description: 'Tenant ID for routing inbound SMS' })
  @ApiResponse({ status: 200, description: 'Inbound message queued' })
  @ApiResponse({ status: 401, description: 'Invalid Twilio signature' })
  async receiveInbound(
    @Param('tenantId') tenantId: string,
    @Body() dto: InboundSmsDto,
    @Headers('x-twilio-signature') twilioSignature: string,
    @Req() req: Request,
  ): Promise<{ success: boolean; queued: boolean }> {
    const authToken = this.configService.get<string>('TWILIO_AUTH_TOKEN');

    if (!authToken) {
      if (process.env.NODE_ENV === 'production') {
        throw new InternalServerErrorException('TWILIO_AUTH_TOKEN not configured');
      }
      this.logger.warn(
        'TWILIO_AUTH_TOKEN not configured — skipping webhook signature verification (dev only)',
      );
    } else {
      if (!twilioSignature) {
        this.metricsService.authFailuresTotal.inc({ reason: 'webhook_signature' });
        throw new UnauthorizedException('Missing X-Twilio-Signature header');
      }

      const url = `${req.protocol}://${req.get('host')}${req.originalUrl}`;
      const params = req.body as Record<string, string>;
      const data =
        url +
        Object.keys(params)
          .sort()
          .reduce((acc, key) => acc + key + params[key], '');
      const expectedSignature = crypto
        .createHmac('sha1', authToken)
        .update(Buffer.from(data, 'utf-8'))
        .digest('base64');

      const expBuf = Buffer.from(expectedSignature);
      const sigBuf = Buffer.from(twilioSignature);
      const invalid = expBuf.length !== sigBuf.length || !crypto.timingSafeEqual(expBuf, sigBuf);
      if (invalid) {
        this.logger.warn('Invalid Twilio webhook signature');
        this.metricsService.authFailuresTotal.inc({ reason: 'webhook_signature' });
        throw new UnauthorizedException('Invalid Twilio signature');
      }
    }

    const phoneHash = crypto.createHash('sha256').update(dto.From).digest('hex');

    await this.smsQueue.add('process-inbound', {
      tenantId,
      phoneHash,
      body: dto.Body,
      twilioSid: dto.MessageSid,
    });

    this.metricsService.smsMessagesTotal.labels('INBOUND', 'queued').inc();
    return { success: true, queued: true };
  }
}

