import { Injectable, Logger, NotFoundException, InternalServerErrorException } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { PrismaService } from '../common/services/prisma.service';
import { EncryptionService } from '../common/services/encryption.service';
import { SmsDirection, SmsStatus } from '@prisma/client';
import { SmsThreadResponseDto, SmsMessageResponseDto } from './dto/sms.dto';
import Twilio from 'twilio';

@Injectable()
export class SmsThreadService {
  private readonly logger = new Logger(SmsThreadService.name);

  constructor(
    private readonly prisma: PrismaService,
    private readonly encryption: EncryptionService,
    private readonly configService: ConfigService,
  ) {}

  /**
   * List threads with last message, ordered by lastMessageAt desc.
   */
  async getThreads(
    tenantId: string,
    limit: number = 20,
    offset: number = 0,
  ): Promise<{ threads: SmsThreadResponseDto[]; total: number }> {
    const where = { tenantId };

    const [threads, total] = await Promise.all([
      this.prisma.smsThread.findMany({
        where,
        include: {
          customer: true,
          messages: {
            orderBy: { createdAt: 'desc' as const },
            take: 1,
          },
        },
        orderBy: { lastMessageAt: 'desc' },
        take: limit,
        skip: offset,
      }),
      this.prisma.smsThread.count({ where }),
    ]);

    return { threads: threads as unknown as SmsThreadResponseDto[], total };
  }

  /**
   * Get messages for a thread, mark thread as read (unreadCount = 0).
   */
  async getMessages(
    tenantId: string,
    threadId: string,
    limit: number = 50,
    offset: number = 0,
  ): Promise<{ messages: SmsMessageResponseDto[]; total: number }> {
    const thread = await this.prisma.smsThread.findFirst({
      where: { id: threadId, tenantId },
    });

    if (!thread) {
      throw new NotFoundException(`SMS thread ${threadId} not found`);
    }

    // Mark as read
    await this.prisma.smsThread.update({
      where: { id: threadId },
      data: { unreadCount: 0 },
    });

    const where = { threadId };

    const [messages, total] = await Promise.all([
      this.prisma.smsMessage.findMany({
        where,
        orderBy: { createdAt: 'desc' },
        take: limit,
        skip: offset,
      }),
      this.prisma.smsMessage.count({ where }),
    ]);

    const decryptedMessages = messages.map(m => ({
      ...m,
      body: this.encryption.decrypt(m.body),
    }));
    return { messages: decryptedMessages as unknown as SmsMessageResponseDto[], total };
  }

  /**
   * Send an outbound SMS message in an existing thread via Twilio.
   */
  async sendMessage(tenantId: string, threadId: string, body: string): Promise<unknown> {
    const thread = await this.prisma.smsThread.findFirst({
      where: { id: threadId, tenantId },
      include: { customer: true },
    });

    if (!thread) {
      throw new NotFoundException(`SMS thread ${threadId} not found`);
    }

    const accountSid = this.configService.get<string>('TWILIO_ACCOUNT_SID');
    const authToken = this.configService.get<string>('TWILIO_AUTH_TOKEN');
    const fromPhone = this.configService.get<string>('TWILIO_PHONE_NUMBER');

    let twilioSid: string | null = null;
    if (accountSid && authToken && fromPhone) {
      const toPhone = this.encryption.decrypt((thread as any).customer.encryptedPhone);
      const client = Twilio(accountSid, authToken);
      const msg = await client.messages.create({ to: toPhone, from: fromPhone, body });
      twilioSid = msg.sid;
    } else if (process.env.NODE_ENV === 'production') {
      throw new InternalServerErrorException('Twilio not configured');
    } else {
      this.logger.warn('Twilio not configured — skipping outbound SMS (dev only)');
    }

    const message = await this.prisma.smsMessage.create({
      data: {
        threadId,
        direction: SmsDirection.OUTBOUND,
        body: this.encryption.encrypt(body),
        status: SmsStatus.SENT,
        twilioSid,
      },
    });

    await this.prisma.smsThread.update({
      where: { id: threadId },
      data: { lastMessageAt: new Date() },
    });

    this.logger.log(`Outbound SMS sent in thread ${threadId}`);
    return message;
  }

  /**
   * Receive an inbound SMS. Finds thread by phoneHash, creates INBOUND message,
   * increments unreadCount.
   */
  async receiveInbound(
    tenantId: string,
    phoneHash: string,
    body: string,
    twilioSid?: string,
  ): Promise<unknown> {
    // Fix 1: Idempotency — Twilio retries failed webhooks up to 11 times
    if (twilioSid) {
      const existing = await this.prisma.smsMessage.findFirst({ where: { twilioSid } });
      if (existing) {
        this.logger.log(`Duplicate inbound SMS ignored: twilioSid=${twilioSid}`);
        return { ...existing, body: this.encryption.decrypt(existing.body) };
      }
    }

    // Fix 3: Include tenantId in thread lookup to prevent cross-tenant leak
    const thread = await this.prisma.smsThread.findFirst({
      where: { phoneHash, tenantId },
    });

    if (!thread) {
      this.logger.warn(`No thread found for phoneHash in tenant`);
      throw new NotFoundException(`No SMS thread found for the given phone`);
    }

    const message = await this.prisma.smsMessage.create({
      data: {
        threadId: thread.id,
        direction: SmsDirection.INBOUND,
        body: this.encryption.encrypt(body),
        status: SmsStatus.DELIVERED,
        twilioSid: twilioSid ?? null,
      },
    });

    await this.prisma.smsThread.update({
      where: { id: thread.id },
      data: {
        unreadCount: { increment: 1 },
        lastMessageAt: new Date(),
      },
    });

    this.logger.log(`Inbound SMS received in thread ${thread.id}`);
    return message;
  }

  /**
   * Find or create an SMS thread for a customer.
   */
  async getOrCreateThread(
    tenantId: string,
    customerId: string,
    phoneHash: string,
  ): Promise<unknown> {
    const existing = await this.prisma.smsThread.findFirst({
      where: { tenantId, customerId, phoneHash },
    });

    if (existing) {
      return existing;
    }

    const thread = await this.prisma.smsThread.create({
      data: {
        tenantId,
        customerId,
        phoneHash,
      },
    });

    this.logger.log(`Created SMS thread ${thread.id} for customer ${customerId}`);
    return thread;
  }
}

