import { Test, TestingModule } from '@nestjs/testing';
import { NotFoundException, InternalServerErrorException } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { SmsThreadService } from './sms-thread.service';
import { PrismaService } from '../common/services/prisma.service';
import { EncryptionService } from '../common/services/encryption.service';
import { SmsDirection, SmsStatus } from '@prisma/client';

jest.mock('twilio', () => {
  const mockCreate = jest.fn();
  const mockClient = { messages: { create: mockCreate } };
  const twilioFn = jest.fn(() => mockClient);
  (twilioFn as unknown as Record<string, unknown>)._mockCreate = mockCreate;
  return twilioFn;
});

import Twilio from 'twilio';
const mockTwilioCreate = (Twilio as unknown as Record<string, jest.Mock>)._mockCreate;

const TENANT_ID = 'tenant-uuid-001';

function mockThread(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    id: 'thread-uuid-001',
    tenantId: TENANT_ID,
    customerId: 'cust-uuid-001',
    phoneHash: 'hash-123456',
    unreadCount: 0,
    lastMessageAt: new Date('2026-04-28T10:00:00Z'),
    createdAt: new Date(),
    updatedAt: new Date(),
    customer: { id: 'cust-uuid-001', encryptedPhone: 'enc-phone' },
    messages: [],
    ...overrides,
  };
}

function mockMessage(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    id: 'msg-uuid-001',
    threadId: 'thread-uuid-001',
    direction: SmsDirection.INBOUND,
    body: 'Test message',
    status: SmsStatus.DELIVERED,
    twilioSid: 'SM123456789',
    createdAt: new Date('2026-04-28T10:00:00Z'),
    updatedAt: new Date(),
    ...overrides,
  };
}

const mockEncryption = {
  encrypt: jest.fn((v: string) => v),
  decrypt: jest.fn((v: string) => v),
};

const mockConfigService = {
  get: jest.fn(),
};

describe('SmsThreadService', () => {
  let service: SmsThreadService;
  let prisma: {
    smsThread: {
      findMany: jest.Mock;
      findFirst: jest.Mock;
      count: jest.Mock;
      create: jest.Mock;
      update: jest.Mock;
    };
    smsMessage: {
      findMany: jest.Mock;
      findFirst: jest.Mock;
      count: jest.Mock;
      create: jest.Mock;
    };
  };

  beforeEach(async () => {
    jest.clearAllMocks();
    mockEncryption.encrypt.mockImplementation((v: string) => v);
    mockEncryption.decrypt.mockImplementation((v: string) => v);
    mockConfigService.get.mockReturnValue(undefined);

    prisma = {
      smsThread: {
        findMany: jest.fn(),
        findFirst: jest.fn(),
        count: jest.fn(),
        create: jest.fn(),
        update: jest.fn(),
      },
      smsMessage: {
        findMany: jest.fn(),
        findFirst: jest.fn(),
        count: jest.fn(),
        create: jest.fn(),
      },
    };

    const module: TestingModule = await Test.createTestingModule({
      providers: [
        SmsThreadService,
        { provide: PrismaService, useValue: prisma },
        { provide: EncryptionService, useValue: mockEncryption },
        { provide: ConfigService, useValue: mockConfigService },
      ],
    }).compile();

    service = module.get(SmsThreadService);
  });

  describe('getThreads', () => {
    it('should return paginated threads', async () => {
      const threads = [mockThread()];
      prisma.smsThread.findMany.mockResolvedValueOnce(threads);
      prisma.smsThread.count.mockResolvedValueOnce(1);

      const result = await service.getThreads(TENANT_ID, 20, 0);

      expect(result).toEqual({ threads, total: 1 });
      expect(prisma.smsThread.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          where: { tenantId: TENANT_ID },
          take: 20,
          skip: 0,
        }),
      );
      expect(prisma.smsThread.count).toHaveBeenCalledWith({ where: { tenantId: TENANT_ID } });
    });

    it('should use default pagination', async () => {
      prisma.smsThread.findMany.mockResolvedValueOnce([]);
      prisma.smsThread.count.mockResolvedValueOnce(0);

      await service.getThreads(TENANT_ID);

      expect(prisma.smsThread.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          take: 20,
          skip: 0,
        }),
      );
      expect(prisma.smsThread.count).toHaveBeenCalledTimes(1);
    });

    it('should include customer and last message', async () => {
      const threads = [mockThread()];
      prisma.smsThread.findMany.mockResolvedValueOnce(threads);
      prisma.smsThread.count.mockResolvedValueOnce(1);

      await service.getThreads(TENANT_ID);

      expect(prisma.smsThread.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          include: expect.objectContaining({
            customer: true,
            messages: expect.any(Object),
          }),
        }),
      );
      expect(prisma.smsThread.findMany).toHaveBeenCalledTimes(1);
    });
  });

  describe('getMessages', () => {
    it('should return messages and mark thread as read', async () => {
      const thread = mockThread();
      const messages = [mockMessage()];
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.findMany.mockResolvedValueOnce(messages);
      prisma.smsMessage.count.mockResolvedValueOnce(1);
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      const result = await service.getMessages(TENANT_ID, 'thread-uuid-001', 50, 0);

      expect(result).toEqual({ messages, total: 1 });
      expect(mockEncryption.decrypt).toHaveBeenCalledWith('Test message');
      expect(prisma.smsThread.findFirst).toHaveBeenCalledWith({
        where: { id: 'thread-uuid-001', tenantId: TENANT_ID },
      });
      expect(prisma.smsThread.update).toHaveBeenCalledWith({
        where: { id: 'thread-uuid-001' },
        data: { unreadCount: 0 },
      });
    });

    it('should throw NotFoundException if thread not found', async () => {
      prisma.smsThread.findFirst.mockResolvedValueOnce(null);

      await expect(service.getMessages(TENANT_ID, 'nonexistent', 50, 0)).rejects.toThrow(
        NotFoundException,
      );
      expect(prisma.smsThread.findFirst).toHaveBeenCalledTimes(1);
    });

    it('should apply pagination to messages', async () => {
      const thread = mockThread();
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.findMany.mockResolvedValueOnce([]);
      prisma.smsMessage.count.mockResolvedValueOnce(0);
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      await service.getMessages(TENANT_ID, 'thread-uuid-001', 30, 10);

      expect(prisma.smsMessage.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          take: 30,
          skip: 10,
        }),
      );
      expect(prisma.smsMessage.findMany).toHaveBeenCalledTimes(1);
    });

    it('should use default limit=50 and offset=0 when not provided', async () => {
      const thread = mockThread();
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.findMany.mockResolvedValueOnce([]);
      prisma.smsMessage.count.mockResolvedValueOnce(0);
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      const result = await service.getMessages(TENANT_ID, 'thread-uuid-001');

      expect(result).toEqual({ messages: [], total: 0 });
      expect(prisma.smsMessage.findMany).toHaveBeenCalledWith(
        expect.objectContaining({
          take: 50,
          skip: 0,
        }),
      );
      expect(prisma.smsMessage.count).toHaveBeenCalledTimes(1);
    });
  });

  describe('sendMessage', () => {
    it('should call Twilio and store twilioSid when configured', async () => {
      mockConfigService.get.mockImplementation((key: string) => {
        const cfg: Record<string, string> = {
          TWILIO_ACCOUNT_SID: 'AC-test',
          TWILIO_AUTH_TOKEN: 'auth-token',
          TWILIO_PHONE_NUMBER: '+1555000000',
        };
        return cfg[key];
      });
      mockEncryption.decrypt.mockReturnValueOnce('+393331234567');
      mockTwilioCreate.mockResolvedValueOnce({ sid: 'SM-sent-001' });

      const thread = mockThread();
      const message = mockMessage({
        direction: SmsDirection.OUTBOUND,
        status: SmsStatus.SENT,
        twilioSid: 'SM-sent-001',
      });
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.create.mockResolvedValueOnce(message);
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      const result = await service.sendMessage(TENANT_ID, 'thread-uuid-001', 'Hello');

      expect(result).toEqual(message);
      expect(mockTwilioCreate).toHaveBeenCalledWith(
        expect.objectContaining({ to: '+393331234567', from: '+1555000000', body: 'Hello' }),
      );
      expect(prisma.smsMessage.create).toHaveBeenCalledWith({
        data: expect.objectContaining({
          twilioSid: 'SM-sent-001',
          direction: SmsDirection.OUTBOUND,
        }),
      });
      expect(prisma.smsThread.update).toHaveBeenCalledWith(
        expect.objectContaining({
          data: expect.objectContaining({ lastMessageAt: expect.any(Date) }),
        }),
      );
    });

    it('should skip Twilio call and log warning in dev when not configured', async () => {
      mockConfigService.get.mockReturnValueOnce(undefined);
      const origEnv = process.env.NODE_ENV;
      process.env.NODE_ENV = 'development';

      const thread = mockThread();
      const message = mockMessage({ direction: SmsDirection.OUTBOUND, twilioSid: null });
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.create.mockResolvedValueOnce(message);
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      const result = await service.sendMessage(TENANT_ID, 'thread-uuid-001', 'Dev msg');

      expect(result).toBeDefined();
      expect(mockTwilioCreate).not.toHaveBeenCalled();
      expect(prisma.smsMessage.create).toHaveBeenCalledWith(
        expect.objectContaining({ data: expect.objectContaining({ twilioSid: null }) }),
      );
      process.env.NODE_ENV = origEnv;
    });

    it('should throw InternalServerErrorException in production when Twilio not configured', async () => {
      mockConfigService.get.mockReturnValueOnce(undefined);
      const origEnv = process.env.NODE_ENV;
      process.env.NODE_ENV = 'production';

      const thread = mockThread();
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);

      await expect(service.sendMessage(TENANT_ID, 'thread-uuid-001', 'Hi')).rejects.toThrow(
        InternalServerErrorException,
      );
      expect(prisma.smsMessage.create).not.toHaveBeenCalled();
      process.env.NODE_ENV = origEnv;
    });

    it('should throw NotFoundException when thread not found', async () => {
      prisma.smsThread.findFirst.mockResolvedValueOnce(null);

      await expect(service.sendMessage(TENANT_ID, 'nonexistent', 'Hi')).rejects.toThrow(
        NotFoundException,
      );
      expect(prisma.smsMessage.create).not.toHaveBeenCalled();
    });

    it('should include tenantId in thread lookup', async () => {
      mockConfigService.get.mockReturnValueOnce(undefined);
      const origEnv = process.env.NODE_ENV;
      process.env.NODE_ENV = 'test';

      const thread = mockThread();
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.create.mockResolvedValueOnce(mockMessage());
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      await service.sendMessage('tenant-2', 'thread-uuid-001', 'Test');

      expect(prisma.smsThread.findFirst).toHaveBeenCalledWith(
        expect.objectContaining({
          where: expect.objectContaining({ tenantId: 'tenant-2' }),
        }),
      );
      process.env.NODE_ENV = origEnv;
    });

    it('should include customer in thread lookup for phone decryption', async () => {
      mockConfigService.get.mockImplementation((key: string) => {
        const cfg: Record<string, string> = {
          TWILIO_ACCOUNT_SID: 'AC-test',
          TWILIO_AUTH_TOKEN: 'auth-token',
          TWILIO_PHONE_NUMBER: '+1555000000',
        };
        return cfg[key];
      });
      mockEncryption.decrypt.mockReturnValueOnce('+393331234567');
      mockTwilioCreate.mockResolvedValueOnce({ sid: 'SM-abc' });

      const thread = mockThread();
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.create.mockResolvedValueOnce(mockMessage());
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      await service.sendMessage(TENANT_ID, 'thread-uuid-001', 'Hello');

      expect(prisma.smsThread.findFirst).toHaveBeenCalledWith(
        expect.objectContaining({ include: { customer: true } }),
      );
      expect(mockEncryption.decrypt).toHaveBeenCalledWith('enc-phone');
    });
  });

  describe('receiveInbound', () => {
    it('should create inbound message and increment unreadCount', async () => {
      prisma.smsMessage.findFirst.mockResolvedValueOnce(null);
      const thread = mockThread();
      const inboundMsg = mockMessage({
        direction: SmsDirection.INBOUND,
        status: SmsStatus.DELIVERED,
        twilioSid: 'SM123',
      });
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.create.mockResolvedValueOnce(inboundMsg);
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      const result = await service.receiveInbound(
        TENANT_ID,
        'hash-123456',
        'Incoming msg',
        'SM123',
      );

      expect(result).toEqual(inboundMsg);
      expect((result as Record<string, unknown>).direction).toBe(SmsDirection.INBOUND);
      expect(mockEncryption.encrypt).toHaveBeenCalledWith('Incoming msg');
      expect(prisma.smsMessage.create).toHaveBeenCalledWith({
        data: expect.objectContaining({
          threadId: 'thread-uuid-001',
          direction: SmsDirection.INBOUND,
          body: 'Incoming msg',
          status: SmsStatus.DELIVERED,
          twilioSid: 'SM123',
        }),
      });
      expect(prisma.smsThread.update).toHaveBeenCalledWith(
        expect.objectContaining({
          where: { id: 'thread-uuid-001' },
          data: expect.objectContaining({ unreadCount: { increment: 1 } }),
        }),
      );
    });

    it('should return existing message when twilioSid already processed (idempotency)', async () => {
      const existing = mockMessage({ twilioSid: 'SM-DUPLICATE' });
      prisma.smsMessage.findFirst.mockResolvedValueOnce(existing);

      const result = await service.receiveInbound(
        TENANT_ID,
        'hash-123456',
        'Duplicate',
        'SM-DUPLICATE',
      );

      expect(result).toEqual(existing);
      expect(mockEncryption.decrypt).toHaveBeenCalledWith('Test message');
      expect(prisma.smsMessage.create).not.toHaveBeenCalled();
      expect(prisma.smsThread.findFirst).not.toHaveBeenCalled();
    });

    it('should check duplicate by twilioSid when provided', async () => {
      prisma.smsMessage.findFirst.mockResolvedValueOnce(null);
      const thread = mockThread();
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.create.mockResolvedValueOnce(mockMessage());
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      await service.receiveInbound(TENANT_ID, 'hash-123456', 'New msg', 'SM-NEW');

      expect(prisma.smsMessage.findFirst).toHaveBeenCalledWith({ where: { twilioSid: 'SM-NEW' } });
    });

    it('should skip idempotency check when twilioSid is absent', async () => {
      const thread = mockThread();
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.create.mockResolvedValueOnce(mockMessage({ twilioSid: null }));
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      await service.receiveInbound(TENANT_ID, 'hash-123456', 'No sid');

      expect(prisma.smsMessage.findFirst).not.toHaveBeenCalled();
      expect(prisma.smsMessage.create).toHaveBeenCalledWith({
        data: expect.objectContaining({ twilioSid: null }),
      });
      expect(prisma.smsThread.update).toHaveBeenCalledTimes(1);
    });

    it('should include tenantId in thread findFirst (multi-tenant isolation)', async () => {
      prisma.smsMessage.findFirst.mockResolvedValueOnce(null);
      const thread = mockThread();
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);
      prisma.smsMessage.create.mockResolvedValueOnce(mockMessage());
      prisma.smsThread.update.mockResolvedValueOnce(thread);

      await service.receiveInbound(TENANT_ID, 'hash-123456', 'msg', 'SM-999');

      expect(prisma.smsThread.findFirst).toHaveBeenCalledWith({
        where: { phoneHash: 'hash-123456', tenantId: TENANT_ID },
      });
    });

    it('should throw NotFoundException when no thread matches phoneHash+tenantId', async () => {
      prisma.smsMessage.findFirst.mockResolvedValueOnce(null);
      prisma.smsThread.findFirst.mockResolvedValueOnce(null);

      await expect(
        service.receiveInbound(TENANT_ID, 'unknown-hash', 'msg', 'SM-001'),
      ).rejects.toThrow(NotFoundException);
      expect(prisma.smsMessage.create).not.toHaveBeenCalled();
    });
  });

  describe('getOrCreateThread', () => {
    it('should return existing thread when found', async () => {
      const thread = mockThread();
      prisma.smsThread.findFirst.mockResolvedValueOnce(thread);

      const result = await service.getOrCreateThread(TENANT_ID, 'cust-uuid-001', 'hash-123456');

      expect(result).toEqual(thread);
      expect((result as Record<string, unknown>).id).toBe('thread-uuid-001');
      expect(prisma.smsThread.create).not.toHaveBeenCalled();
      expect(prisma.smsThread.findFirst).toHaveBeenCalledTimes(1);
    });

    it('should create new thread when none exists', async () => {
      const thread = mockThread();
      prisma.smsThread.findFirst.mockResolvedValueOnce(null);
      prisma.smsThread.create.mockResolvedValueOnce(thread);

      const result = await service.getOrCreateThread(TENANT_ID, 'cust-uuid-001', 'hash-123456');

      expect(result).toEqual(thread);
      expect(prisma.smsThread.create).toHaveBeenCalledWith({
        data: {
          tenantId: TENANT_ID,
          customerId: 'cust-uuid-001',
          phoneHash: 'hash-123456',
        },
      });
      expect(prisma.smsThread.create).toHaveBeenCalledTimes(1);
    });

    it('should scope thread lookup by tenantId, customerId, and phoneHash', async () => {
      prisma.smsThread.findFirst.mockResolvedValueOnce(null);
      prisma.smsThread.create.mockResolvedValueOnce(mockThread());

      await service.getOrCreateThread('tenant-2', 'customer-99', 'hash-xyz');

      expect(prisma.smsThread.findFirst).toHaveBeenCalledWith({
        where: { tenantId: 'tenant-2', customerId: 'customer-99', phoneHash: 'hash-xyz' },
      });
      expect(prisma.smsThread.findFirst).toHaveBeenCalledTimes(1);
    });
  });
});

