import { Test, TestingModule } from '@nestjs/testing';
import { UnauthorizedException, InternalServerErrorException } from '@nestjs/common';
import { ConfigService } from '@nestjs/config';
import { getQueueToken } from '@nestjs/bullmq';
import { Request } from 'express';
import { SmsThreadController, SmsWebhookController } from './sms-thread.controller';
import { SmsThreadService } from './sms-thread.service';
import { MetricsService } from '../common/metrics/metrics.service';
import { SmsDirection, SmsStatus } from '@prisma/client';
import * as crypto from 'crypto';

const TENANT_ID = 'tenant-uuid-001';

function mockThread(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    id: 'thread-uuid-001',
    tenantId: TENANT_ID,
    customerId: 'cust-uuid-001',
    phoneHash: 'hash-123456',
    unreadCount: 0,
    lastMessageAt: new Date('2026-04-28T10:00:00Z'),
    createdAt: new Date(),
    updatedAt: new Date(),
    customer: { id: 'cust-uuid-001', encryptedPhone: 'enc-phone' },
    messages: [],
    ...overrides,
  };
}

function mockMessage(overrides: Record<string, unknown> = {}): Record<string, unknown> {
  return {
    id: 'msg-uuid-001',
    threadId: 'thread-uuid-001',
    direction: SmsDirection.INBOUND,
    body: 'Test message',
    status: SmsStatus.DELIVERED,
    twilioSid: 'SM123456789',
    createdAt: new Date('2026-04-28T10:00:00Z'),
    updatedAt: new Date(),
    ...overrides,
  };
}

function buildTwilioSignature(
  authToken: string,
  url: string,
  params: Record<string, string>,
): string {
  const data =
    url +
    Object.keys(params)
      .sort()
      .reduce((acc, key) => acc + key + params[key], '');
  return crypto.createHmac('sha1', authToken).update(Buffer.from(data, 'utf-8')).digest('base64');
}

function sha256(input: string): string {
  return crypto.createHash('sha256').update(input).digest('hex');
}

describe('SmsThreadController', () => {
  let controller: SmsThreadController;

  const mockService = {
    getThreads: jest.fn(),
    getMessages: jest.fn(),
    sendMessage: jest.fn(),
  };

  beforeEach(async () => {
    jest.clearAllMocks();

    const module: TestingModule = await Test.createTestingModule({
      controllers: [SmsThreadController],
      providers: [{ provide: SmsThreadService, useValue: mockService }],
    }).compile();

    controller = module.get(SmsThreadController);
  });

  describe('getThreads', () => {
    it('should return paginated threads with meta', async () => {
      const threads = [mockThread()];
      mockService.getThreads.mockResolvedValueOnce({ threads, total: 1 });

      const result = await controller.getThreads(TENANT_ID, 20, 0);

      expect(result.success).toBe(true);
      expect(result.data).toEqual(threads);
      expect(result.meta.total).toBe(1);
      expect(mockService.getThreads).toHaveBeenCalledWith(TENANT_ID, 20, 0);
    });

    it('should pass tenantId to service', async () => {
      mockService.getThreads.mockResolvedValueOnce({ threads: [], total: 0 });

      await controller.getThreads('tenant-2', 10, 5);

      expect(mockService.getThreads).toHaveBeenCalledWith('tenant-2', 10, 5);
      expect(mockService.getThreads).toHaveBeenCalledTimes(1);
    });

    it('should handle empty thread list', async () => {
      mockService.getThreads.mockResolvedValueOnce({ threads: [], total: 0 });

      const result = await controller.getThreads(TENANT_ID, 20, 0);

      expect(result.data).toEqual([]);
      expect(result.meta.total).toBe(0);
      expect(mockService.getThreads).toHaveBeenCalledTimes(1);
    });

    it('should forward undefined limit and offset to service', async () => {
      mockService.getThreads.mockResolvedValueOnce({ threads: [], total: 0 });

      const result = await controller.getThreads(TENANT_ID, undefined, undefined);

      expect(result.success).toBe(true);
      expect(result.meta.total).toBe(0);
      expect(mockService.getThreads).toHaveBeenCalledWith(TENANT_ID, undefined, undefined);
    });
  });

  describe('getMessages', () => {
    it('should return paginated messages for thread', async () => {
      const messages = [mockMessage()];
      mockService.getMessages.mockResolvedValueOnce({ messages, total: 1 });

      const result = await controller.getMessages(TENANT_ID, 'thread-uuid-001', 50, 0);

      expect(result.success).toBe(true);
      expect(result.data).toEqual(messages);
      expect(result.meta.total).toBe(1);
      expect(mockService.getMessages).toHaveBeenCalledWith(TENANT_ID, 'thread-uuid-001', 50, 0);
    });

    it('should pass threadId and pagination to service', async () => {
      mockService.getMessages.mockResolvedValueOnce({ messages: [], total: 0 });

      await controller.getMessages(TENANT_ID, 'thread-2', 30, 15);

      expect(mockService.getMessages).toHaveBeenCalledWith(TENANT_ID, 'thread-2', 30, 15);
      expect(mockService.getMessages).toHaveBeenCalledTimes(1);
    });

    it('should throw when service throws NotFoundException', async () => {
      mockService.getMessages.mockRejectedValueOnce(
        new (require('@nestjs/common').NotFoundException)('Thread not found'),
      );

      await expect(controller.getMessages(TENANT_ID, 'nonexistent', 50, 0)).rejects.toThrow();
      expect(mockService.getMessages).toHaveBeenCalledTimes(1);
    });

    it('should forward undefined limit and offset to service', async () => {
      mockService.getMessages.mockResolvedValueOnce({ messages: [], total: 0 });

      const result = await controller.getMessages(
        TENANT_ID,
        'thread-uuid-001',
        undefined,
        undefined,
      );

      expect(result.success).toBe(true);
      expect(result.meta.total).toBe(0);
      expect(mockService.getMessages).toHaveBeenCalledWith(
        TENANT_ID,
        'thread-uuid-001',
        undefined,
        undefined,
      );
    });
  });

  describe('sendMessage', () => {
    it('should send message and return success', async () => {
      const message = mockMessage({ direction: SmsDirection.OUTBOUND });
      mockService.sendMessage.mockResolvedValueOnce(message);

      const result = await controller.sendMessage(TENANT_ID, 'thread-uuid-001', {
        body: 'Hello',
      } as never);

      expect(result.success).toBe(true);
      expect(result.data).toEqual(message);
      expect(mockService.sendMessage).toHaveBeenCalledWith(TENANT_ID, 'thread-uuid-001', 'Hello');
    });

    it('should pass tenantId and threadId to service', async () => {
      mockService.sendMessage.mockResolvedValueOnce(mockMessage());

      await controller.sendMessage('tenant-2', 'thread-2', { body: 'Test' } as never);

      expect(mockService.sendMessage).toHaveBeenCalledWith('tenant-2', 'thread-2', 'Test');
      expect(mockService.sendMessage).toHaveBeenCalledTimes(1);
    });

    it('should throw when service throws NotFoundException', async () => {
      mockService.sendMessage.mockRejectedValueOnce(
        new (require('@nestjs/common').NotFoundException)('Thread not found'),
      );

      await expect(
        controller.sendMessage(TENANT_ID, 'nonexistent', { body: 'Hi' } as never),
      ).rejects.toThrow();
      expect(mockService.sendMessage).toHaveBeenCalledTimes(1);
    });
  });
});

describe('SmsWebhookController', () => {
  let controller: SmsWebhookController;

  const mockQueue = { add: jest.fn() };
  const mockConfigService = { get: jest.fn() };
  const mockAuthFailuresTotal = { inc: jest.fn() };
  const mockSmsMessagesTotal = { labels: jest.fn().mockReturnValue({ inc: jest.fn() }) };
  const mockMetrics = {
    authFailuresTotal: mockAuthFailuresTotal,
    smsMessagesTotal: mockSmsMessagesTotal,
  };

  const makeReq = (
    body: Record<string, unknown>,
    protocol = 'http',
    host = 'localhost:3000',
    url = '/sms/webhook/inbound/' + TENANT_ID,
  ): Request =>
    ({ protocol, get: jest.fn().mockReturnValue(host), originalUrl: url, body }) as never;

  beforeEach(async () => {
    jest.clearAllMocks();
    mockConfigService.get.mockReturnValue('test-auth-token');
    mockQueue.add.mockResolvedValue({ id: 'job-1' });

    const module: TestingModule = await Test.createTestingModule({
      controllers: [SmsWebhookController],
      providers: [
        { provide: ConfigService, useValue: mockConfigService },
        { provide: MetricsService, useValue: mockMetrics },
        { provide: getQueueToken('sms-inbound'), useValue: mockQueue },
      ],
    }).compile();

    controller = module.get(SmsWebhookController);
  });

  describe('receiveInbound', () => {
    it('should enqueue job and return queued=true when auth token absent in dev mode', async () => {
      const origEnv = process.env.NODE_ENV;
      process.env.NODE_ENV = 'development';
      mockConfigService.get.mockReturnValueOnce(null);

      const dto = {
        Body: 'Incoming',
        From: '+393331234567',
        To: '+1555000000',
        MessageSid: 'SM123',
      };
      const req = makeReq(dto);
      const result = await controller.receiveInbound(TENANT_ID, dto as never, 'any_sig', req);

      expect(result.success).toBe(true);
      expect(result.queued).toBe(true);
      expect(mockQueue.add).toHaveBeenCalledWith('process-inbound', {
        tenantId: TENANT_ID,
        phoneHash: sha256('+393331234567'),
        body: 'Incoming',
        twilioSid: 'SM123',
      });
      process.env.NODE_ENV = origEnv;
    });

    it('should throw InternalServerErrorException in production when token not configured', async () => {
      const origEnv = process.env.NODE_ENV;
      process.env.NODE_ENV = 'production';
      mockConfigService.get.mockReturnValueOnce(null);

      const dto = { Body: 'msg', From: '+393331234567', To: '+1555000000' };
      const req = makeReq(dto);

      await expect(controller.receiveInbound(TENANT_ID, dto as never, 'sig', req)).rejects.toThrow(
        InternalServerErrorException,
      );
      expect(mockQueue.add).not.toHaveBeenCalled();
      process.env.NODE_ENV = origEnv;
    });

    it('should throw UnauthorizedException and increment metric when signature header missing', async () => {
      mockConfigService.get.mockReturnValueOnce('auth-token');

      const dto = {
        Body: 'Incoming',
        From: '+393331234567',
        To: '+1555000000',
        MessageSid: 'SM456',
      };
      const req = makeReq(dto);

      await expect(controller.receiveInbound(TENANT_ID, dto as never, '', req)).rejects.toThrow(
        UnauthorizedException,
      );
      expect(mockAuthFailuresTotal.inc).toHaveBeenCalledWith({ reason: 'webhook_signature' });
      expect(mockQueue.add).not.toHaveBeenCalled();
    });

    it('should throw UnauthorizedException and increment metric when signature does not match', async () => {
      const authToken = 'auth-token';
      mockConfigService.get.mockReturnValueOnce(authToken);

      const dto = {
        Body: 'Incoming',
        From: '+393331234567',
        To: '+1555000000',
        MessageSid: 'SM789',
      };
      const req = makeReq(dto);
      const wrongSig = Buffer.alloc(28, 'X').toString('base64');

      await expect(
        controller.receiveInbound(TENANT_ID, dto as never, wrongSig, req),
      ).rejects.toThrow(UnauthorizedException);
      expect(mockAuthFailuresTotal.inc).toHaveBeenCalledWith({ reason: 'webhook_signature' });
      expect(mockQueue.add).not.toHaveBeenCalled();
    });

    it('should throw UnauthorizedException when same-length signature has wrong content (timingSafeEqual)', async () => {
      const authToken = 'auth-token';
      mockConfigService.get.mockReturnValueOnce(authToken);

      const dto = {
        Body: 'Incoming',
        From: '+393331234567',
        To: '+1555000000',
        MessageSid: 'SMtse',
      };
      const req = makeReq(dto);
      const wrongSameLengthSig = crypto
        .createHmac('sha1', 'wrong-key')
        .update('wrong-data')
        .digest('base64');

      await expect(
        controller.receiveInbound(TENANT_ID, dto as never, wrongSameLengthSig, req),
      ).rejects.toThrow(UnauthorizedException);
      expect(mockAuthFailuresTotal.inc).toHaveBeenCalledWith({ reason: 'webhook_signature' });
      expect(mockQueue.add).not.toHaveBeenCalled();
    });

    it('should enqueue job with correct payload when valid Twilio signature', async () => {
      const authToken = 'test-auth-token-secret';
      mockConfigService.get.mockReturnValueOnce(authToken);

      const dto = {
        Body: 'Valid sig',
        From: '+393331234567',
        To: '+1555000000',
        MessageSid: 'SMvalid',
      };
      const url = `http://localhost:3000/sms/webhook/inbound/${TENANT_ID}`;
      const expectedSig = buildTwilioSignature(authToken, url, dto as Record<string, string>);

      const req = makeReq(dto);
      const result = await controller.receiveInbound(TENANT_ID, dto as never, expectedSig, req);

      expect(result.success).toBe(true);
      expect(result.queued).toBe(true);
      expect(mockQueue.add).toHaveBeenCalledWith('process-inbound', {
        tenantId: TENANT_ID,
        phoneHash: sha256('+393331234567'),
        body: 'Valid sig',
        twilioSid: 'SMvalid',
      });
    });

    it('should not call auth metrics when signature is valid', async () => {
      const authToken = 'clean-token';
      mockConfigService.get.mockReturnValueOnce(authToken);

      const dto = {
        Body: 'No error',
        From: '+393331234567',
        To: '+1555000000',
        MessageSid: 'SMclean',
      };
      const url = `http://localhost:3000/sms/webhook/inbound/${TENANT_ID}`;
      const expectedSig = buildTwilioSignature(authToken, url, dto as Record<string, string>);

      const req = makeReq(dto);
      await controller.receiveInbound(TENANT_ID, dto as never, expectedSig, req);

      expect(mockAuthFailuresTotal.inc).not.toHaveBeenCalled();
      expect(mockQueue.add).toHaveBeenCalledTimes(1);
    });

    it('should use https protocol when building signature URL', async () => {
      const authToken = 'https-token';
      mockConfigService.get.mockReturnValueOnce(authToken);

      const dto = {
        Body: 'HTTPS msg',
        From: '+393331234567',
        To: '+1555000000',
        MessageSid: 'SMhttps',
      };
      const url = `https://secure.example.com/sms/webhook/inbound/${TENANT_ID}`;
      const expectedSig = buildTwilioSignature(authToken, url, dto as Record<string, string>);

      const req = makeReq(dto, 'https', 'secure.example.com');
      const result = await controller.receiveInbound(TENANT_ID, dto as never, expectedSig, req);

      expect(result.success).toBe(true);
      expect(mockQueue.add).toHaveBeenCalledTimes(1);
    });

    it('should enqueue job with undefined twilioSid when MessageSid absent', async () => {
      const origEnv = process.env.NODE_ENV;
      process.env.NODE_ENV = 'development';
      mockConfigService.get.mockReturnValueOnce(null);

      const dto = { Body: 'No SID', From: '+393331234567', To: '+1555000000' };
      const req = makeReq(dto);
      await controller.receiveInbound(TENANT_ID, dto as never, '', req);

      expect(mockQueue.add).toHaveBeenCalledWith('process-inbound', {
        tenantId: TENANT_ID,
        phoneHash: sha256('+393331234567'),
        body: 'No SID',
        twilioSid: undefined,
      });
      process.env.NODE_ENV = origEnv;
    });

    it('should build URL from protocol, host, and originalUrl for signature check', async () => {
      const authToken = 'url-build-token';
      mockConfigService.get.mockReturnValueOnce(authToken);

      const dto = {
        Body: 'URL test',
        From: '+393331234567',
        To: '+1555000000',
        MessageSid: 'SMurl',
      };
      const url = `http://api.example.com/sms/webhook/inbound/${TENANT_ID}`;
      const expectedSig = buildTwilioSignature(authToken, url, dto as Record<string, string>);

      const req = makeReq(dto, 'http', 'api.example.com');
      const result = await controller.receiveInbound(TENANT_ID, dto as never, expectedSig, req);

      expect(result.success).toBe(true);
      expect((req as never as { get: jest.Mock }).get).toHaveBeenCalledWith('host');
    });
  });
});

